import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../utils/AuthContext';

const navItems = [
  { to: '/dashboard', emoji: '🏠', label: 'Dashboard' },
  { to: '/profile', emoji: '👤', label: 'My Profile' },
  { to: '/roadmap', emoji: '📆', label: '30-Day Roadmap' },
  { to: '/tests/coding', emoji: '💻', label: 'Coding Test' },
  { to: '/tests/aptitude', emoji: '🧠', label: 'Aptitude Test' },
  { to: '/tests/communication', emoji: '🗣️', label: 'Communication' },
  { to: '/resources', emoji: '📚', label: 'Resources' },
  { to: '/results', emoji: '📊', label: 'My Results' },
];

const sidebarStyles = `
  .placeai-sidebar {
    width: 252px;
    min-height: 100vh;
    position: fixed;
    top: 0;
    left: 0;
    z-index: 100;
    display: flex;
    flex-direction: column;
    background: linear-gradient(180deg, #080c18 0%, #0b1020 50%, #080c18 100%);
    border-right: 1px solid rgba(99, 102, 241, 0.11);
    transition: transform 0.3s ease;
  }

  .placeai-sidebar::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background:
      radial-gradient(ellipse 200px 240px at 15% 12%, rgba(99, 102, 241, 0.08) 0%, transparent 70%),
      radial-gradient(ellipse 160px 180px at 85% 85%, rgba(139, 92, 246, 0.05) 0%, transparent 70%);
    pointer-events: none;
  }

  .placeai-logo-area {
    padding: 20px 18px 16px;
    display: flex;
    align-items: center;
    gap: 10px;
    border-bottom: 1px solid rgba(99, 102, 241, 0.09);
    position: relative;
  }

  .placeai-logo-gem {
    width: 36px;
    height: 36px;
    border-radius: 9px;
    background: linear-gradient(135deg, #6366f1 0%, #8b5cf6 55%, #06b6d4 100%);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 17px;
    box-shadow: 0 0 20px rgba(99, 102, 241, 0.5), 0 2px 8px rgba(0,0,0,0.5);
    flex-shrink: 0;
  }

  .placeai-logo-text {
    font-size: 18px;
    font-weight: 800;
    font-family: 'Space Grotesk', sans-serif;
    background: linear-gradient(135deg, #e2e8f0 0%, #a5b4fc 60%, #67e8f9 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    letter-spacing: -0.3px;
  }

  .placeai-logo-badge {
    margin-left: auto;
    font-size: 8.5px;
    font-weight: 700;
    color: rgba(99, 102, 241, 0.65);
    background: rgba(99, 102, 241, 0.09);
    border: 1px solid rgba(99, 102, 241, 0.18);
    border-radius: 4px;
    padding: 2px 5px;
    letter-spacing: 0.5px;
    flex-shrink: 0;
  }

  .placeai-nav {
    flex: 1;
    padding: 12px 10px;
    display: flex;
    flex-direction: column;
    gap: 1px;
    overflow-y: auto;
  }

  .placeai-nav-section {
    font-size: 9px;
    font-weight: 700;
    color: rgba(100, 116, 139, 0.5);
    letter-spacing: 1.3px;
    text-transform: uppercase;
    padding: 10px 10px 5px;
  }

  .placeai-nav-item {
    display: flex;
    align-items: center;
    gap: 9px;
    padding: 8px 11px;
    border-radius: 9px;
    cursor: pointer;
    color: rgba(148, 163, 184, 0.75);
    font-size: 13px;
    font-weight: 500;
    transition: all 0.15s ease;
    text-decoration: none;
    border: 1px solid transparent;
    position: relative;
    overflow: hidden;
  }

  .placeai-nav-item:hover {
    color: #cbd5e1;
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(99, 102, 241, 0.1);
  }

  .placeai-nav-item.active {
    color: #f1f5f9;
    background: linear-gradient(135deg, rgba(99, 102, 241, 0.16) 0%, rgba(139, 92, 246, 0.1) 100%);
    border-color: rgba(99, 102, 241, 0.28);
    box-shadow: 0 2px 12px rgba(99, 102, 241, 0.12), inset 0 1px 0 rgba(255,255,255,0.05);
  }

  .placeai-nav-item.active::before {
    content: '';
    position: absolute;
    left: 0;
    top: 22%;
    bottom: 22%;
    width: 2.5px;
    background: linear-gradient(180deg, #818cf8, #a78bfa);
    border-radius: 0 2px 2px 0;
    box-shadow: 0 0 8px rgba(129, 140, 248, 0.6);
  }

  .placeai-nav-icon {
    width: 28px;
    height: 28px;
    border-radius: 7px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    background: rgba(255,255,255,0.03);
    flex-shrink: 0;
    transition: all 0.15s ease;
  }

  .placeai-nav-item.active .placeai-nav-icon {
    background: rgba(99, 102, 241, 0.18);
    box-shadow: 0 0 10px rgba(99, 102, 241, 0.18);
  }

  .placeai-nav-item:hover .placeai-nav-icon {
    background: rgba(255,255,255,0.05);
  }

  .placeai-divider {
    height: 1px;
    background: rgba(99, 102, 241, 0.07);
    margin: 6px 10px;
  }

  .placeai-bottom {
    padding: 10px 10px 14px;
    border-top: 1px solid rgba(99, 102, 241, 0.09);
  }

  .placeai-user-card {
    display: flex;
    align-items: center;
    gap: 9px;
    padding: 9px 11px;
    border-radius: 9px;
    cursor: pointer;
    transition: all 0.15s ease;
    border: 1px solid transparent;
  }

  .placeai-user-card:hover {
    background: rgba(239, 68, 68, 0.07);
    border-color: rgba(239, 68, 68, 0.13);
  }

  .placeai-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    background: linear-gradient(135deg, #6366f1, #8b5cf6);
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 12px;
    color: white;
    flex-shrink: 0;
    box-shadow: 0 0 10px rgba(99, 102, 241, 0.28);
  }

  .placeai-user-name {
    font-size: 12.5px;
    font-weight: 600;
    color: #cbd5e1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 130px;
  }

  .placeai-user-action {
    font-size: 10px;
    color: rgba(239, 68, 68, 0.6);
    margin-top: 1px;
  }

  .placeai-main {
    flex: 1;
    margin-left: 252px;
    min-height: 100vh;
    background: var(--bg);
  }

  @media (max-width: 768px) {
    .placeai-sidebar { transform: translateX(-100%); }
    .placeai-main { margin-left: 0; }
  }
`;

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <>
      <style>{sidebarStyles}</style>
      <div className="app-container">
        <aside className="placeai-sidebar">
          {/* Logo */}
          <div className="placeai-logo-area">
            <div className="placeai-logo-gem">🎯</div>
            <span className="placeai-logo-text">PlaceAI</span>
            <span className="placeai-logo-badge">BETA</span>
          </div>

          {/* Navigation */}
          <nav className="placeai-nav">
            <div className="placeai-nav-section">Overview</div>
            {navItems.slice(0, 3).map(item => (
              <NavLink
                key={item.to}
                to={item.to}
                className={({ isActive }) => `placeai-nav-item${isActive ? ' active' : ''}`}
              >
                <div className="placeai-nav-icon">{item.emoji}</div>
                <span>{item.label}</span>
              </NavLink>
            ))}

            <div className="placeai-divider" />
            <div className="placeai-nav-section">Practice</div>
            {navItems.slice(3, 6).map(item => (
              <NavLink
                key={item.to}
                to={item.to}
                className={({ isActive }) => `placeai-nav-item${isActive ? ' active' : ''}`}
              >
                <div className="placeai-nav-icon">{item.emoji}</div>
                <span>{item.label}</span>
              </NavLink>
            ))}

            <div className="placeai-divider" />
            <div className="placeai-nav-section">Insights</div>
            {navItems.slice(6).map(item => (
              <NavLink
                key={item.to}
                to={item.to}
                className={({ isActive }) => `placeai-nav-item${isActive ? ' active' : ''}`}
              >
                <div className="placeai-nav-icon">{item.emoji}</div>
                <span>{item.label}</span>
              </NavLink>
            ))}
          </nav>

          {/* User / Logout */}
          <div className="placeai-bottom">
            <div className="placeai-user-card" onClick={handleLogout} title="Click to logout">
              <div className="placeai-avatar">{user?.name?.[0]?.toUpperCase() || 'U'}</div>
              <div style={{ overflow: 'hidden' }}>
                <div className="placeai-user-name">{user?.name}</div>
                <div className="placeai-user-action">Sign out →</div>
              </div>
            </div>
          </div>
        </aside>

        <main className="placeai-main">
          <Outlet />
        </main>
      </div>
    </>
  );
}
